import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"妖力","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/5.能量池/妖力.md","filePath":"4.资源分区/5.能量池/妖力.md"}'),d={name:"4.资源分区/5.能量池/妖力.md"};function l(p,a,i,_,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"妖力",tabindex:"-1"},[s("妖力 "),e("a",{class:"header-anchor",href:"#妖力","aria-label":'Permalink to "妖力"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新秩序009")])])],-1),o('<h1 id="妖力-1" tabindex="-1">妖力 <a class="header-anchor" href="#妖力-1" aria-label="Permalink to &quot;妖力&quot;">​</a></h1><p>妖力<br> 妖力是传统的东方能量池，作为妖怪常用的能量，其能量性质更为诡异多变。在能量的使用过程中，可能会被他人认为使用者的阵营偏向更接近妖类。</p><p>D+500<br> 强化者开启妖力能量池，能量池的关键属性为风度+耐力。<br> 妖力的恢复方式为：<br> 1、在阴暗的环境/夜晚下进行一次短休息，恢复关键属性检定点妖力。<br> 2、在午夜十二点、月食发生时、天地异象产生时、可恢复能量池上限的妖力。<br> 无论如何，一日内只能恢复至多等于能量池上限3倍的妖力。</p><p>妖力的基础用法有：<br> 迷常：只要妖力池不空，人物在非战斗场景下会令他人下意识的认为自己是一位人群中十分常见的普通人（如在农村时是一位村民、在城市中是一个上班族/学生等），如果人物表现的比较突兀，则目击者可以进行一个DC为7的意志豁免，豁免通过则本能力失效。这是一个D级别影响心灵来源的思维控制效果。<br> 惑心：在人物施加可豁免的情绪异常点数时，可以支付2点妖力，使得该情绪异常点数上升2点。（该流程在豁免进行前。）</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
